import React from "react";

const CartPage = ({ cart, setCart, setView }) => {
  const removeItem = (id) => {
    setCart((c) => c.filter((it) => it.productId !== id));
  };

  const changeQty = (id, delta) => {
    setCart((c) =>
      c.map((it) =>
        it.productId === id
          ? { ...it, qty: Math.max(1, it.qty + delta) }
          : it
      )
    );
  };

  const total = cart.reduce((s, it) => s + it.price * it.qty, 0);

  const checkout = () => {
    if (cart.length === 0) return alert("Cart is empty");
    // placeholder checkout
    alert(`Checked out ${cart.length} items. Total ₹${total}`);
    setCart([]);
    setView("products");
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Your Cart</h2>

      {cart.length === 0 && <p>Your cart is empty.</p>}

      {cart.map((it) => (
        <div key={it.productId} style={{ display: "flex", gap: 12, alignItems: "center", borderBottom: "1px solid #eee", padding: 8 }}>
          {it.image && <img src={it.image} alt={it.name} style={{ width: 80, height: 80, objectFit: "cover" }} />}

          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 600 }}>{it.name}</div>
            <div>₹{it.price}</div>
            <div style={{ display: "flex", gap: 8, marginTop: 6 }}>
              <button onClick={() => changeQty(it.productId, -1)}>-</button>
              <div style={{ padding: "4px 8px" }}>{it.qty}</div>
              <button onClick={() => changeQty(it.productId, 1)}>+</button>
            </div>
          </div>

          <div style={{ textAlign: "right" }}>
            <div>₹{it.price * it.qty}</div>
            <button onClick={() => removeItem(it.productId)}>Remove</button>
          </div>
        </div>
      ))}

      <div style={{ marginTop: 12 }}>
        <strong>Total: ₹{total}</strong>
      </div>

      <div style={{ marginTop: 12 }}>
        <button onClick={checkout}>Checkout</button>
        <button onClick={() => setView("products")} style={{ marginLeft: 8 }}>Continue Shopping</button>
      </div>
    </div>
  );
};

export default CartPage;
